-- >>> seeds/20_scale_setup.sql
-- =============================================================================
-- 10. SCALE SEED SETUP
-- =============================================================================

-- Memory tuning for bulk operations
SET work_mem = '32MB';
SET maintenance_work_mem = '128MB';

-- ---------------------------------------------------------------------------
-- Utility: language picker with weighted distribution
-- ---------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.seed_pick_language(r float)
RETURNS text LANGUAGE sql IMMUTABLE AS $$
  SELECT CASE
    WHEN r < 0.40 THEN 'en'
    WHEN r < 0.55 THEN 'tr'
    WHEN r < 0.65 THEN 'es'
    WHEN r < 0.73 THEN 'fr'
    WHEN r < 0.80 THEN 'de'
    WHEN r < 0.85 THEN 'ar'
    WHEN r < 0.89 THEN 'ja'
    WHEN r < 0.92 THEN 'ko'
    WHEN r < 0.95 THEN 'pt'
    WHEN r < 0.98 THEN 'zh'
    ELSE 'it'
  END;
$$;

-- ---------------------------------------------------------------------------
-- Utility: country picker with weighted distribution
-- ---------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.seed_pick_country(r double precision)
RETURNS text LANGUAGE sql IMMUTABLE AS $$
  SELECT CASE
    WHEN r < 0.25 THEN 'US'
    WHEN r < 0.40 THEN 'TR'
    WHEN r < 0.50 THEN 'ES'
    WHEN r < 0.58 THEN 'FR'
    WHEN r < 0.65 THEN 'DE'
    WHEN r < 0.72 THEN 'GB'
    WHEN r < 0.77 THEN 'JP'
    WHEN r < 0.82 THEN 'KR'
    WHEN r < 0.87 THEN 'BR'
    WHEN r < 0.91 THEN 'SA'
    WHEN r < 0.94 THEN 'IT'
    WHEN r < 0.96 THEN 'MX'
    WHEN r < 0.98 THEN 'IN'
    ELSE 'CA'
  END;
$$;

-- Pre-computed bcrypt hash for 'seedpassword' (avoids per-row crypt() cost)
CREATE OR REPLACE FUNCTION public.seed_password_hash()
RETURNS text LANGUAGE sql IMMUTABLE AS $$
  SELECT '$2a$06$RzK1X5hN5KqJF5V8OqXYXOqYXOqYXOqYXOqYXOqYXOqYXOqYXOqYX'::text;
$$;

